import React, { useState } from 'react';

const App = () => {
  const [channels, setChannels] = useState(['Channel 1', 'Channel 2', 'Channel 3']);
  const [selectedChannel, setSelectedChannel] = useState('Channel 1');
  const [messages, setMessages] = useState({ Channel 1: ['Message 1', 'Message 2'], Channel 2: ['Message 3'], Channel 3: [] });
  const [searchTerm, setSearchTerm] = useState('');
  const [newMessage, setNewMessage] = useState('');

  const handleSearch = (e) => {
    setSearchTerm(e.target.value);
  };

  const handleSendMessage = (e) => {
    e.preventDefault();
    setMessages({ ...messages, [selectedChannel]: [...messages[selectedChannel], newMessage] });
    setNewMessage('');
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-80 bg-[#B7D7CD] p-4 shadow-md">
        <h2>Channels</h2>
        <ul>
          {channels.map((channel, index) => (
            <li key={index} onClick={() => setSelectedChannel(channel)} className={`cursor-pointer ${selectedChannel === channel ? 'bg-[#411C56] text-[#B7D7CD]' : ''}`}>{channel}</li>
          ))}
        </ul>
        <input type="search" value={searchTerm} onChange={handleSearch} placeholder="Search messages" className="w-full p-2 bg-transparent border-b"/>
        <button onClick={handleSendMessage} className="bg-[#C06C88] p-2">Send Message</button>
      </div>
      <div className="w-80 bg-[#B7D7CD] p-4 shadow-md ml-4">
        <h2>Messages</h2>
        <ul>
          {Object.values(messages).flat().filter((message) => message.toLowerCase().includes(searchTerm.toLowerCase())).map((message, index) => (
            <li key={index}>{message}</li>
          ))}
        </ul>
      </div>
      <div className="w-20 bg-[#411C56] p-4 shadow-md ml-4">
        <svg width="20" height="20"><rect x="10" y="10" width="10" height="10" fill="#B7D7CD"/></svg>
      </div>
    </div>
  );
};

export default App;
